-- ========================
-- CONSULTAS
-- ========================

-- Dados básicos
SELECT * FROM tbl_clientes;
SELECT * FROM tbl_pedidos;
SELECT * FROM tbl_itens_pedido;

-- Pedido com detalhes
SELECT 
  p.id AS pedido,
  c.nome AS cliente,
  pr.nome AS produto,
  ip.quantidade,
  ip.subtotal
FROM tbl_pedidos p
JOIN tbl_clientes c ON p.cliente_id = c.id
JOIN tbl_itens_pedido ip ON ip.pedido_id = p.id
JOIN tbl_produtos pr ON ip.produto_id = pr.id;

-- Faturamento por dia
SELECT 
  DATE(p.criado_em) AS data,
  SUM(ip.subtotal) AS faturamento
FROM tbl_pedidos p
JOIN tbl_itens_pedido ip ON ip.pedido_id = p.id
WHERE p.status <> 'CANCELADO'
GROUP BY DATE(p.criado_em)
ORDER BY data;